// Classify task type and select optimal model
const req = $input.first().json;
const { task_type, prompt, budget = 10.0, max_latency_sec = 5 } = req;

const models = {
  'code':      { id: 'claude-sonnet-4-20250514', provider: 'anthropic', cost_per_1k: 0.015, speed: 'medium', context: 200000 },
  'writing':   { id: 'gpt-4o-2024-08-06',       provider: 'openai',    cost_per_1k: 0.015, speed: 'slow',   context: 128000 },
  'quick':     { id: 'gpt-4o-mini-2024-07-18',  provider: 'openai',    cost_per_1k: 0.0004, speed: 'fast', context: 128000 },
  'analysis':  { id: 'gpt-4o-2024-08-06',       provider: 'openai',    cost_per_1k: 0.015, speed: 'slow',   context: 128000 },
  'creative':  { id: 'claude-sonnet-4-20250514', provider: 'anthropic', cost_per_1k: 0.015, speed: 'medium', context: 200000 },
  'default':   { id: 'gpt-4o-mini-2024-07-18',  provider: 'openai',    cost_per_1k: 0.0004, speed: 'fast', context: 128000 },
};

const selected = models[task_type] || models['default'];

// Budget check
const estimated_cost = (prompt.length / 4) * selected.cost_per_1k / 1000;
if (estimated_cost > budget) {
  return [{ json: { error: 'Budget exceeded', estimated_cost, budget } }];
}

return [{ json: { selected_model: selected.id, provider: selected.provider, prompt, estimated_cost, context_window: selected.context } }];
